import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';

const ProjectDetail = () => {
  const { id } = useParams();
  const { user } = useContext(AuthContext);
  const [project, setProject] = useState(null);
  const [sprints, setSprints] = useState([]);
  const [riskData, setRiskData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProjectData();
  }, [id]);

  const fetchProjectData = async () => {
    try {
      const [projectRes, sprintsRes] = await Promise.all([
        api.get(`/projects/${id}`),
        api.get(`/sprints?projectId=${id}`)
      ]);

      setProject(projectRes.data.project);
      setSprints(sprintsRes.data.sprints || []);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching project data:', error);
      setLoading(false);
    }
  };

  const handleRiskAnalysis = async () => {
    try {
      const response = await api.get(`/ai/risk/${id}`);
      setRiskData(response.data);
      fetchProjectData(); // Refresh to get updated risk info
    } catch (error) {
      alert(error.response?.data?.message || 'Error analyzing risk');
    }
  };

  if (loading) {
    return <div className="loading">Loading project...</div>;
  }

  if (!project) {
    return <div className="alert alert-error">Project not found</div>;
  }

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <div>
          <h1>{project.name}</h1>
          <p>{project.description || 'No description'}</p>
        </div>
        <div>
          <Link to="/projects" className="btn btn-secondary">Back to Projects</Link>
          {user.role === 'PM' && (
            <button onClick={handleRiskAnalysis} className="btn btn-primary" style={{ marginLeft: '10px' }}>
              Analyze Risk
            </button>
          )}
        </div>
      </div>

      <div className="card">
        <div className="card-header">Project Information</div>
        <p><strong>Created:</strong> {new Date(project.createdAt).toLocaleDateString()}</p>
        <p><strong>Start Date:</strong> {new Date(project.startDate).toLocaleDateString()}</p>
        <p><strong>Team Members:</strong> {project.teamMembers?.length || 0}</p>
        <p>
          <strong>Risk Level:</strong>{' '}
          <span className={`risk-${project.riskLevel?.toLowerCase()}`}>
            {project.riskLevel || 'Low'}
          </span>
        </p>
        {project.riskScore > 0 && (
          <p><strong>Risk Score:</strong> {project.riskScore}/100</p>
        )}
      </div>

      {riskData && (
        <div className="card">
          <div className="card-header">AI Risk Analysis</div>
          <div className={`alert alert-${riskData.riskLevel === 'High' ? 'error' : riskData.riskLevel === 'Medium' ? 'warning' : 'success'}`}>
            <strong>Risk Level: {riskData.riskLevel}</strong>
            <p style={{ marginTop: '10px', whiteSpace: 'pre-line' }}>{riskData.explanation}</p>
          </div>
          {riskData.features && (
            <div style={{ marginTop: '15px' }}>
              <h4>Risk Factors:</h4>
              <ul>
                {riskData.features.missedDeadlines > 0 && (
                  <li>Missed Deadlines: {riskData.features.missedDeadlines.toFixed(1)}%</li>
                )}
                {riskData.features.taskSpilloverRate > 0 && (
                  <li>Task Spillover Rate: {riskData.features.taskSpilloverRate.toFixed(1)}%</li>
                )}
                {riskData.features.bugCount > 0 && (
                  <li>Bug Count: {riskData.features.bugCount}</li>
                )}
                {riskData.features.velocityFluctuation > 0 && (
                  <li>Velocity Fluctuation: {riskData.features.velocityFluctuation.toFixed(1)}%</li>
                )}
              </ul>
            </div>
          )}
        </div>
      )}

      <div className="card">
        <div className="card-header">Sprints</div>
        {sprints.length === 0 ? (
          <p>No sprints yet. {user.role === 'PM' && <Link to="/sprints">Create one</Link>}</p>
        ) : (
          <table className="table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Status</th>
                <th>Planned Velocity</th>
                <th>Actual Velocity</th>
                <th>Health Score</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {sprints.map(sprint => (
                <tr key={sprint._id}>
                  <td>{sprint.name}</td>
                  <td>
                    <span className={`badge badge-${sprint.status === 'Completed' ? 'success' : sprint.status === 'Active' ? 'info' : 'warning'}`}>
                      {sprint.status}
                    </span>
                  </td>
                  <td>{sprint.plannedVelocity}</td>
                  <td>{sprint.actualVelocity || '-'}</td>
                  <td>{sprint.sprintHealthScore || '-'}</td>
                  <td>
                    <Link to={`/sprints/${sprint._id}`} className="btn btn-primary btn-sm">
                      View
                    </Link>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default ProjectDetail;
